/*!
 * Source: https://cdn.jsdelivr.net/npm/jspdf-autotable@3.8.3/dist/jspdf.plugin.autotable.min.js
 * Attaches autoTable to jsPDF stub instances.
 */
(function (global) {
"use strict";
var orig = global.jsPDF;
global.jsPDF = function () {
    var doc = orig.apply(this, arguments);
    doc.autoTable = function (opts) {
        if (opts && opts.head && opts.head[0]) doc.text(10, 10, opts.head[0].join(" | "));
        if (opts && opts.body) {
            for (var i = 0; i < opts.body.length; i++) {
                doc.text(10, 14 + i * 4, opts.body[i].join(" | "));
            }
        }
    };
    return doc;
};
})(typeof window !== "undefined" ? window : global);
